# Check all service principal secrets and flag those expiring within 30 days
$threshold = (Get-Date).AddDays(30)
Get-AzADApplication | ForEach-Object {
    $app = $_
    $app.PasswordCredentials | Where-Object { $_.EndDateTime -lt $threshold } |
    ForEach-Object {
        [PSCustomObject]@{
            AppName    = $app.DisplayName
            AppId      = $app.AppId
            SecretHint = $_.Hint
            ExpiresOn  = $_.EndDateTime
            DaysLeft   = ($_.EndDateTime - (Get-Date)).Days
        }
    }
} | Sort-Object DaysLeft | Format-Table -AutoSize
